import{_ as t,o as a,c as s,a2 as o}from"./chunks/framework.DTa47_fH.js";const u=JSON.parse('{"title":"How SWAO Works","description":"","frontmatter":{},"headers":[],"relativePath":"how-it-works.md","filePath":"how-it-works.md"}'),n={name:"how-it-works.md"};function r(i,e,d,l,p,c){return a(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="how-swao-works" tabindex="-1">How SWAO Works <a class="header-anchor" href="#how-swao-works" aria-label="Permalink to &quot;How SWAO Works&quot;">​</a></h1><p>SWAO analyses a cloud application and produces an auditor-grade assessment report in a single command -- or through the guided terminal interface. No external services, no data uploads, no call-home.</p><hr><h2 id="the-guided-interface-tui" tabindex="-1">The guided interface (TUI) <a class="header-anchor" href="#the-guided-interface-tui" aria-label="Permalink to &quot;The guided interface (TUI)&quot;">​</a></h2><p>When you run <code>swao</code> without arguments, the <strong>terminal user interface</strong> opens. It walks you through every step without needing to remember commands.</p><h3 id="main-menu" tabindex="-1">Main menu <a class="header-anchor" href="#main-menu" aria-label="Permalink to &quot;Main menu&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SWAO -- Sovereign Workload Assessment and Onboarding</span></span>
<span class="line"><span>Community  v0.4.8</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  1  Workspace Setup       init + LLM + credentials wizard</span></span>
<span class="line"><span>  2  Health Check          swao doctor</span></span>
<span class="line"><span>  3  Run Assessment        Application / Audit / Landing Zone + more</span></span>
<span class="line"><span>  4  Generate Report       swao report (text / PDF)</span></span>
<span class="line"><span>  5  Publish HTML          swao publish -- self-contained HTML file</span></span>
<span class="line"><span>  6  Export BI             star schema / PowerBI / Tableau</span></span>
<span class="line"><span>  7  Portfolio Operations  multi-app aggregate (Premium)</span></span>
<span class="line"><span>  8  Generate TF Modules   swao generate-tf</span></span>
<span class="line"><span>  9  Tools                 lenses / licence / credentials / help</span></span>
<span class="line"><span>  0  Exit</span></span></code></pre></div><p>Use the arrow keys or type the number to navigate.</p><blockquote><p>See also: <a href="/samples/#sample-10">Sample Gallery -- TUI Main Menu</a></p></blockquote><h3 id="setup-wizard" tabindex="-1">Setup Wizard <a class="header-anchor" href="#setup-wizard" aria-label="Permalink to &quot;Setup Wizard&quot;">​</a></h3><p>If this is your first time, start here. The wizard asks:</p><ol><li><strong>Workspace name</strong> -- a short identifier for the engagement folder.</li><li><strong>Application name</strong> -- the workload you are assessing.</li><li><strong>Compliance frameworks</strong> -- GDPR is pre-selected. Nine community frameworks are available (GDPR, AI 10 Pillars, COBIT 5, NIST SP 800-66 R2, ISO 27001, PCI DSS, SOC 2, BSI C5, DORA). Add more at any time via <code>swao framework install</code>.</li><li><strong>LLM provider</strong> -- Anthropic Claude, OpenAI, a local Ollama model, or a deterministic stub for offline use.</li></ol><p>The wizard creates a ready-to-use workspace folder on disk.</p><h3 id="health-check" tabindex="-1">Health Check <a class="header-anchor" href="#health-check" aria-label="Permalink to &quot;Health Check&quot;">​</a></h3><p>Before running an assessment, select <strong>Health Check</strong> (item 2) to verify that the workspace is healthy. Each probe reports <code>ok</code> or a specific action to take:</p><table tabindex="0"><thead><tr><th>Probe</th><th>What it checks</th></tr></thead><tbody><tr><td>Licence</td><td>Edition detected and valid</td></tr><tr><td>Playwright</td><td>Dynamic analysis readiness</td></tr><tr><td>MCP</td><td>Model Context Protocol server configuration</td></tr><tr><td>Compliance catalogues</td><td>Framework files present and consistent</td></tr><tr><td>Import templates</td><td>Ingestion folder structure</td></tr><tr><td>Traceability</td><td>Audit-grade signal fields enabled</td></tr><tr><td>BI export bundle</td><td>Previous export integrity</td></tr></tbody></table><blockquote><p>See also: <a href="/samples/#sample-12">Sample Gallery -- Health Check</a></p></blockquote><h3 id="run-assessment" tabindex="-1">Run Assessment <a class="header-anchor" href="#run-assessment" aria-label="Permalink to &quot;Run Assessment&quot;">​</a></h3><p>Select <strong>3. Run Assessment</strong> from the main menu. SWAO asks which assessment type to run:</p><table tabindex="0"><thead><tr><th>Option</th><th>What it does</th></tr></thead><tbody><tr><td>Application Assessment</td><td>Analyses your application source code</td></tr><tr><td>Landing Zone Assessment</td><td>Checks your cloud infrastructure configuration</td></tr><tr><td>Audit Assessment</td><td>Coming soon -- human-led audit</td></tr><tr><td>LLM Assessment</td><td>Coming soon -- AI model benchmarking</td></tr><tr><td>Hybrid Assessment</td><td>Coming soon -- combined source + audit</td></tr></tbody></table><p>Select an assessment type, confirm, and SWAO runs automatically. A live progress bar shows each pass as it completes.</p><hr><h2 id="the-assessment-pipeline" tabindex="-1">The assessment pipeline <a class="header-anchor" href="#the-assessment-pipeline" aria-label="Permalink to &quot;The assessment pipeline&quot;">​</a></h2><p>An <strong>Application Assessment</strong> runs up to 14 analysis passes. Each pass is independent and auditable.</p><table tabindex="0"><thead><tr><th>Pass</th><th>What it does (business view)</th></tr></thead><tbody><tr><td>1. Inventory</td><td>Maps the languages, frameworks, and dependencies in your codebase</td></tr><tr><td>2. State analysis</td><td>Identifies stateful components: databases, session storage, caches</td></tr><tr><td>3. Data classification</td><td>Finds personal data fields, PII columns, residency markers</td></tr><tr><td>4. Context ingestion</td><td>Reads your CMDB, workshop transcripts, and architecture docs</td></tr><tr><td>5. SBOM</td><td>Produces a Software Bill of Materials with licence classification</td></tr><tr><td>6. Twelve-factor</td><td>Checks cloud-readiness against the 12-factor application standard</td></tr><tr><td>7. Egress analysis</td><td>Maps outbound calls and third-party data transfers</td></tr><tr><td>8. Cryptography</td><td>Reviews hashing, TLS configuration, and secrets handling</td></tr><tr><td>9. Migration synthesis</td><td>Synthesises a 7R verdict (Retire, Retain, Rehost, Replatform, Refactor, Re-architect, Repurchase)</td></tr><tr><td>10. Compliance evaluation</td><td>Maps findings to the active compliance frameworks</td></tr><tr><td>11. Landing zone readiness</td><td>Checks fit against your cloud landing zone requirements</td></tr><tr><td>12. Security posture</td><td>Identifies common vulnerability patterns in the source code</td></tr><tr><td>13. Dynamic analysis</td><td>Browser crawl for UI surface mapping</td></tr><tr><td>14. Evidence gallery</td><td>Collects screenshots and artefacts for the audit record</td></tr></tbody></table><p>The first three passes (inventory, state, data classification) are deterministic -- no LLM required. Passes 4, 9, and 10 call the LLM to produce human-readable rationale on every signal and compliance verdict.</p><hr><h2 id="the-html-publication" tabindex="-1">The HTML publication <a class="header-anchor" href="#the-html-publication" aria-label="Permalink to &quot;The HTML publication&quot;">​</a></h2><p>After an assessment, SWAO generates a <strong>self-contained HTML file</strong> you can open in any browser, email to a client, or use offline in an air-gapped environment.</p><p>The publication includes:</p><ul><li><strong>Executive view</strong> -- 7R verdict, coverage score, top risks in plain language.</li><li><strong>Technical view</strong> -- all signals with derivation, evidence links, and pass breakdowns.</li><li><strong>Compliance view</strong> -- per-framework control table with outcome and rationale.</li><li><strong>Auditor view</strong> -- per-control audit record: outcome, rationale, evidence, assessor, timestamp. Filterable by framework and verdict.</li><li><strong>Evidence gallery</strong> -- screenshots and artefacts from the assessment, embedded for offline delivery.</li><li><strong>Run history</strong> -- duration, LLM cost, files assessed, per-pass breakdown.</li></ul><p>The HTML file contains everything. No server, no internet connection, no account needed to open it.</p><p><strong>To generate the publication:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">swao</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-app</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># opens: wsp/publications/latest/index.html</span></span></code></pre></div><blockquote><p>See also: <a href="/samples/#sample-14">Sample Gallery -- Publish HTML TUI</a> and <a href="/samples/#sample-04">PowerBI dashboard screenshots</a></p></blockquote><hr><h2 id="mcp-integration" tabindex="-1">MCP integration <a class="header-anchor" href="#mcp-integration" aria-label="Permalink to &quot;MCP integration&quot;">​</a></h2><p>SWAO can connect to <strong>Claude AI</strong> via the <strong>Model Context Protocol (MCP)</strong>. Once connected, you can ask Claude questions about your assessment findings in natural language -- without leaving your conversation.</p><p>Example questions you can ask Claude after connecting:</p><ul><li>&quot;What are the top compliance gaps for this application?&quot;</li><li>&quot;Summarise the landing zone fit/gap findings.&quot;</li><li>&quot;Show me all signals assessed by the rule engine.&quot;</li><li>&quot;What is the 7R migration verdict and why?&quot;</li></ul><h3 id="how-to-connect" tabindex="-1">How to connect <a class="header-anchor" href="#how-to-connect" aria-label="Permalink to &quot;How to connect&quot;">​</a></h3><ol><li>Run <code>swao doctor</code> (or select <strong>2. Health Check</strong> in the TUI) -- the MCP probe shows the server path.</li><li>In Claude Desktop: Settings &gt; Developer &gt; MCP Servers &gt; Add. Paste the path.</li><li>Restart Claude Desktop.</li></ol><blockquote><p>See also: <a href="/samples/#sample-15">Sample Gallery -- MCP connector setup</a> and <a href="/samples/#sample-16">MCP challenge in Claude</a></p></blockquote><p>SWAO starts the MCP server automatically when Claude connects. All assessment data stays on your machine -- MCP only exposes a query interface, not the raw files.</p><p>Available tools via MCP:</p><table tabindex="0"><thead><tr><th>Tool</th><th>What it does</th></tr></thead><tbody><tr><td><code>swao_assess</code></td><td>Trigger a new assessment from within Claude</td></tr><tr><td><code>swao_report</code></td><td>Get a structured summary of the latest assessment</td></tr><tr><td><code>swao_signal_detail</code></td><td>Look up a specific signal by ID</td></tr><tr><td><code>swao_compliance_status</code></td><td>Query compliance control outcomes by framework</td></tr><tr><td><code>swao_lz_fit</code></td><td>Get the landing zone fit/gap summary</td></tr><tr><td><code>swao_run_history</code></td><td>List recent assessment runs with cost and duration</td></tr></tbody></table><hr><h2 id="powerbi-dashboards" tabindex="-1">PowerBI dashboards <a class="header-anchor" href="#powerbi-dashboards" aria-label="Permalink to &quot;PowerBI dashboards&quot;">​</a></h2><p>The <strong>BI export bundle</strong> produced by every assessment is a set of 17 CSV tables in a star-schema layout. Any BI tool can load it.</p><p>For <strong>Power BI Desktop</strong> users, SWAO ships pre-built templates in your workspace at <code>wsp/templates/powerbi/</code>:</p><table tabindex="0"><thead><tr><th>Template</th><th>Tier</th><th>Pages</th></tr></thead><tbody><tr><td><code>swao-report.pbit</code> (single app)</td><td>Consultant + Enterprise</td><td>Overview, Compliance, Signals, Risks, Auditor, Run Stats</td></tr><tr><td><code>swao-portfolio.pbit</code> (multi-app)</td><td>Enterprise</td><td>Portfolio Overview, App Heatmap, Compliance, Risk &amp; 7R, Wave Sequencing, Auditor Roll-up</td></tr></tbody></table><p>To open a template:</p><ol><li>Open the <code>.pbit</code> file in Power BI Desktop.</li><li>When prompted for <code>SWAOExportPath</code>, paste the path to the <code>star/</code> folder inside your latest assessment export.</li><li>Click <strong>Load</strong>. The dashboard refreshes with your data.</li></ol><p>For step-by-step instructions on customising the template, see the <a href="/templates/AUTHORING-GUIDE">Authoring guide</a>.</p><hr><h2 id="what-stays-on-your-machine" tabindex="-1">What stays on your machine <a class="header-anchor" href="#what-stays-on-your-machine" aria-label="Permalink to &quot;What stays on your machine&quot;">​</a></h2><p>SWAO is <strong>file-only</strong> by design:</p><ul><li>No telemetry. No usage data sent anywhere.</li><li>No hosted endpoint. The assessment engine runs entirely on your machine.</li><li>No call-home. The binary does not check for updates or send error reports.</li><li>LLM calls go directly from your machine to the provider you configured (Anthropic, OpenAI, or Ollama). SWAO does not proxy or store them.</li><li>The HTML publication, BI export, and PowerBI dashboard are local files. Share them only when and how you choose.</li></ul>`,58)])])}const m=t(n,[["render",r]]);export{u as __pageData,m as default};
